#nullable enable // autogenerated

using System.Linq;
using MVZ2.Vanilla.Callbacks;
using MVZ2.Vanilla.Properties;
using MVZ2.Vanilla.Shells;
using PVZEngine.Callbacks;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Projectiles
{
    [AutoEntityBehaviourDefinition(VanillaProjectileNames.spike)]
    public class Spike : EntityBehaviourDefinition
    {
        public Spike(string nsp, string name) : base(nsp, name)
        {
            AddTrigger(VanillaLevelCallbacks.POST_PROJECTILE_HIT, PostHitEntityCallback);
        }

        private void PostHitEntityCallback(VanillaLevelCallbacks.PostProjectileHitParams param, CallbackResult result)
        {
            var hitResult = param.hit;
            var projectile = hitResult.Projectile;
            if (!projectile.Definition.HasBehaviour(this))
                return;
            var damageOutput = param.damage;
            if (damageOutput == null)
                return;
            var blocksSlice = damageOutput.GetAllResults().Any(e => e?.ShellDefinition?.BlocksSlice() ?? false);

            var pierceCount = hitResult.Projectile.GetBehaviourField<int>(PROP_PIERCE_COUNT);

            if (!blocksSlice && pierceCount < MAX_PIERCE)
            {
                hitResult.Pierce = true;
                hitResult.Projectile.SetBehaviourField(PROP_PIERCE_COUNT, pierceCount + 1);
            }
        }

        private const int MAX_PIERCE = 3;
        private static readonly VanillaEntityPropertyMeta<int> PROP_PIERCE_COUNT = new("PierceCount");
    }
}
